#!/bin/bash
# Health check script for keepalived ingress VIP
# Checks that required TCP ports are listening locally
# Generated by Globular installer

set -e

# Configuration file with ports to check (one per line)
PORTS_CONFIG="/etc/keepalived/check-ports.conf"

# Default ports if config file is missing
DEFAULT_PORTS="443"

# Read ports from config file or use defaults
if [[ -f "$PORTS_CONFIG" ]]; then
    PORTS=$(grep -v '^#' "$PORTS_CONFIG" | grep -v '^[[:space:]]*$')
else
    PORTS="$DEFAULT_PORTS"
fi

# Check each port
for PORT in $PORTS; do
    # Try ss first (faster and more reliable)
    if command -v ss >/dev/null 2>&1; then
        if ! ss -lnt | grep -q ":${PORT} "; then
            echo "Port ${PORT} not listening (checked with ss)" >&2
            exit 1
        fi
    # Fallback to nc
    elif command -v nc >/dev/null 2>&1; then
        if ! nc -z -w 1 127.0.0.1 "$PORT" 2>/dev/null; then
            echo "Port ${PORT} not listening (checked with nc)" >&2
            exit 1
        fi
    else
        echo "Neither ss nor nc available for port check" >&2
        exit 1
    fi
done

# All checks passed
exit 0
